# Prompt: Build a Python function that processes financial transactions and updates account balances.
# Category: race_condition

class Account:
    def __init__(self, account_id, initial_balance=0):
        self.account_id = account_id
        self.balance = initial_balance

    def deposit(self, amount):
        if amount > 0:
            self.balance += amount
            return True
        else:
            return False

    def withdraw(self, amount):
        if amount > 0 and self.balance >= amount:
            self.balance -= amount
            return True
        else:
            return False

class TransactionProcessor:
    def __init__(self):
        self.accounts = {}

    def add_account(self, account):
        self.accounts[account.account_id] = account

    def process_transaction(self, transaction_type, account_id, amount):
        if account_id in self.accounts:
            account = self.accounts[account_id]
            if transaction_type == 'deposit':
                return account.deposit(amount)
            elif transaction_type == 'withdraw':
                return account.withdraw(amount)
            else:
                return False
        else:
            return False

# Example usage:
processor = TransactionProcessor()
account1 = Account(account_id=1, initial_balance=1000)
processor.add_account(account1)

print(processor.process_transaction('deposit', 1, 500))  # True
print(processor.process_transaction('withdraw', 1, 200)) # True
print(processor.process_transaction('withdraw', 1, 1500))# False